export type Address = `0x${string}`;
export type NetworkName = keyof typeof deploymentManifest.environments;
export type ContractName = (typeof contractNames)[number];
export type ContractAbi = readonly Record<string, unknown>[];

export function getContractAddress(network: NetworkName, contract: ContractName): Address {
  const contracts = deploymentManifest.environments[network].contracts as Partial<Record<ContractName, Address | null>>;
  const address = contracts[contract];
  if (!address) {
    throw new Error(`Relay44 contract ${contract} is not deployed on ${network}`);
  }
  return address as Address;
}

export function getContractAbi(contract: ContractName): ContractAbi {
  return contractAbis[contract] as ContractAbi;
}
